function mainJs(a) {
    var arr = a.split(",");
    for(var i = 0;i < arr.length;i++) {
        arr[i] = parseInt(arr[i]);
    }
    //请在此处编写代码
    /*********begin*********/
    let ret = [];
    for (let i = arr.length-1; i > 0; i--){
        let idx = 0;
        for (let j = 0; j <= i; j++){
            idx = arr[idx] > arr[j] ? idx : j;
        }
        let tmp = arr[i];
        arr[i] = arr[idx];
        arr[idx] = tmp;
        ret.push(idx);
    }
    return ret;
    /*********end*********/
}
